const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };

const error    = $input.first().json;

const workflow  = error.workflow?.name  ?? 'Unknown workflow';
const node      = error.execution?.lastNodeExecuted ?? 'Unknown node';
const errorMsg  = error.execution?.error?.message   ?? 'No error message available';
const errorType = error.execution?.error?.name      ?? 'Error';
const execId    = error.execution?.id               ?? 'unknown';
const execUrl   = $env.N8N_BASE_URL
  ? `${$env.N8N_BASE_URL}/execution/${execId}`
  : 'Execution URL not available — set N8N_BASE_URL env var';

log('Error received from workflow:', workflow);
log('Failed node:', node);
log('Error:', errorMsg);

const slackText =
  `:red_circle: *Workflow failed: ${workflow}*\n` +
  `*Failed node:* ${node}\n` +
  `*Error type:* ${errorType}\n` +
  `*Message:* ${errorMsg}\n` +
  `*Execution:* ${execUrl}`;

return [{
  json: {
    workflow,
    node,
    errorMsg,
    errorType,
    execId,
    execUrl,
    slackText
  }
}];
